import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"F04: 業外收支純度與收益質量 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F04_業外收支純度與收益質量_投資研究員.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F04_業外收支純度與收益質量_投資研究員.md"}'),n={name:"審計報告庫/財務審計/8064_東捷/20260429/F04_業外收支純度與收益質量_投資研究員.md"};function l(e,i,s,$,g,h){return a(),o("div",null,[...i[0]||(i[0]=[r('<h1 id="f04-業外收支純度與收益質量-投資研究員-審計報告" tabindex="-1">F04: 業外收支純度與收益質量 - 投資研究員 審計報告 <a class="header-anchor" href="#f04-業外收支純度與收益質量-投資研究員-審計報告" aria-label="Permalink to &quot;F04: 業外收支純度與收益質量 - 投資研究員 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>業外收支 (Non-Operating) 規模與組成細項為何？是長期投資收益還是匯兌/利息等雜項損益？是否存在獲利虛胖風險？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：2025 年業外佔稅前比從 84.5% 降至 17.6%，利息/租金佔業外 85%，獲利結構質變改善。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至 2025 年度 (114年度) 最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li><strong>營業收入</strong>：2025 $2,870.7M (YoY +10.2%)；2024 $2,603.9M</li><li><strong>營業淨利</strong>：2025 $276.8M (9.6% margin)；2024 $30.9M (1.2% margin) — <strong>營運巨幅改善</strong></li><li><strong>業外收支合計</strong>：2025 +$59.0M；2024 +$168.5M (較前年 -65%)</li><li><strong>業外佔稅前比</strong>：2025 17.6%；2024 84.5% — <strong>關鍵改善指標</strong></li><li><strong>核心 EPS (扣除業外)</strong>: 2025 ~$1.12；2024 ~$0.12 — 反映真實營運趨勢</li><li><strong>EPS (母公司業主)</strong>：2025 $1.36；2024 $0.79</li></ul></li><li><strong>診斷見解</strong>：2024 年稅前利潤近 85% 來自業外（主要是匯兌 $86.1M），營運本業僅貢獻 $30.9M 稅前，屬典型的「獲利虛胖」模式。2025 年營運利潤暴增至 $276.8M (YoY +797%)，同時業外壓縮至 $59M，且其中 $43.9M 為穩定的利息收入。診斷評級從 <strong>B (持平)</strong> 跳升為 <strong>A- (良)</strong>。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-收益結構透視-income-composition" tabindex="-1">1. 收益結構透視 (Income Composition) <a class="header-anchor" href="#_1-收益結構透視-income-composition" aria-label="Permalink to &quot;1. 收益結構透視 (Income Composition)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2025 年業外 $59.0M：利息 $43.9M (74.4%)、其他收入 $45.3M、其他損失 -$19.1M (含一次性處分損失 $10.4M)、財務成本 -$11.2M。</li><li><strong>深度見解</strong>：利息 $43.9M 源於 $894M 金融資產及定存，屬定常性現金利息。租金 $25.4M + 補助 $6.2M 亦具重複性。剔除一次性處分損失，常態業外約 $69.4M。EPS 貢獻：常態業外約 $0.34/股，一次性損失 -$0.06/股。</li></ul><h3 id="_2-雜訊敏感度分析-noise-sensitivity" tabindex="-1">2. 雜訊敏感度分析 (Noise Sensitivity) <a class="header-anchor" href="#_2-雜訊敏感度分析-noise-sensitivity" aria-label="Permalink to &quot;2. 雜訊敏感度分析 (Noise Sensitivity)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：匯率 1% 對稅前影響：USD ±$2.7M、RMB ±$4.6M。利率 +0.1% 增利息收入 $894K。</li><li><strong>深度見解</strong>：2025 年底外幣淨資產 $758M (USD $271M + RMB $475M + JPY $13M)。USD/TWD 由 2024 年底 32.8 降至 31.4 (台幣升值 4.3%)，解釋 2024 匯兌利 $86.1M 在 2025 反轉為小虧 $0.8M。台幣每升值 5% 減稅前約 $13.5M (EPS -$0.08)；人民幣每貶值 5% 減稅前約 $23M (EPS -$0.14)。</li></ul><h3 id="_3-可持續性評價-sustainability-audit" tabindex="-1">3. 可持續性評價 (Sustainability Audit) <a class="header-anchor" href="#_3-可持續性評價-sustainability-audit" aria-label="Permalink to &quot;3. 可持續性評價 (Sustainability Audit)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：營運利潤 $276.8M 創四年新高，毛利率從 26% 擴至 28%，業外中定常性收入佔 85%+。</li><li><strong>深度見解</strong>：自動化檢測設備營收 $1,672M (+17% YoY)、真空設備 $1,242M。2024 營運低點 ($30.9M) 受資本支出週期影響。若需求維持，營運利潤有望守住 $200-250M/季。利息收入降息後可能縮至 $35-40M，影響有限。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭觀點一</strong>：子公司清算壓力仍存：Far Tech 已清算，但賽博爾雷射 ($95.6M、帳面 $0) 及漢錸 ($816M 帳面) 若持續虧損恐引發減損風險。漢錸 2025 年損失 $489K，衰退壓力未解，後續需追蹤。</li><li><strong>空頭觀點二</strong>：$758M 高額外幣曝險零避險為最大下行風險。2024 匯兌利 $86.1M 在 2025 年全數回吐，證實匯率雙向波動風險。台幣每升值 5% 稅前減約 $13.5M，EPS 影響約-$0.08。</li><li><strong>空頭觀點三</strong>：FVPL $3.6M 來自保險公司債利率變動，屬脆弱性未實現利益。2026 年利率若反彈，公允價值回跌約 $3-5M，構成獲利下行壓力。此類利益在市場波動期可能瞬間轉為損失。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>年報/合併財報</strong>: OK — 引用 2025 Q4 合併財報 P.48-49 業外收支明細、P.54 EPS 計算、P.58 匯率敏感度分析、P.64 外幣資產負債表</li><li><strong>匯率走勢</strong>: OK — 央行/公開資料：2024 年均 32.10、年底 32.78；2025 年均 31.17、年底 31.43</li><li><strong>FinMind</strong>: 資料不足，以年報為基礎提取</li><li><strong>關鍵核對碼</strong>: <ul><li>2025: 業外合計 = 43,867 + 45,335 - 19,055 - 11,179 = 58,968 ✓（對應財報 P.9）</li><li>2024: 業外合計 = 52,639 + 53,799 + 76,159 - 14,071 = 168,526 ✓</li><li>EPS: 2025 $1.36 = 224,775K / 164,818K股；2024 $0.79 = 130,501K / 164,818K股</li><li>匯兌利益 (2024) $86,140K：總利益 $162,618K - 總損失 $76,478K</li></ul></li></ul>',19)])])}const u=t(n,[["render",l]]);export{_ as __pageData,u as default};
